from collections import defaultdict, deque
from dataclasses import dataclass, field
from datetime import datetime, timedelta, timezone
import statistics

class ControlHealthStatus(str, Enum):
    GREEN  = "green"    # Operating within thresholds
    AMBER  = "amber"    # Warning — approaching threshold or single breach
    RED    = "red"      # Critical — threshold breached; requires immediate action
    GREY   = "grey"     # No signal received — possible monitoring gap

@dataclass
class ControlHealthRecord:
    control_id: str
    kpi_name: str
    status: ControlHealthStatus
    current_value: float | None
    target: float | None
    last_signal_time: str
    consecutive_breaches: int = 0
    breach_message: str = ""

class CCMAggregator:
    """
    Receives ControlSignal events, maintains rolling windows per control KPI,
    and computes current health status.
    """
    WINDOW_SIZE = 60    # Keep last 60 signals per KPI for baseline stats
    GREY_TIMEOUT_SECONDS = 300   # No signal in 5 minutes → GREY

    def __init__(self):
        # {(control_id, kpi_name): deque of (timestamp, value)}
        self._windows: dict[tuple, deque] = defaultdict(lambda: deque(maxlen=self.WINDOW_SIZE))
        self._last_signal: dict[tuple, datetime] = {}
        self._consecutive_breaches: dict[tuple, int] = defaultdict(int)

    def ingest(self, signal: ControlSignal) -> None:
        key = (signal.control_id, signal.kpi_name)
        self._windows[key].append((signal.timestamp, signal.kpi_value))
        self._last_signal[key] = datetime.now(timezone.utc)
        if signal.threshold_breached:
            self._consecutive_breaches[key] += 1
        else:
            self._consecutive_breaches[key] = 0

    def health(self, control_id: str, kpi_name: str) -> ControlHealthRecord:
        key = (control_id, kpi_name)
        last_seen = self._last_signal.get(key)
        now = datetime.now(timezone.utc)

        if last_seen is None or (now - last_seen).seconds > self.GREY_TIMEOUT_SECONDS:
            return ControlHealthRecord(
                control_id=control_id, kpi_name=kpi_name,
                status=ControlHealthStatus.GREY,
                current_value=None, target=None,
                last_signal_time=last_seen.isoformat() if last_seen else "never",
                breach_message="No signal received within timeout window",
            )
        window = self._windows[key]
        values = [v for _, v in window]
        current = values[-1] if values else None
        breaches = self._consecutive_breaches[key]

        if breaches >= 2:
            status = ControlHealthStatus.RED
        elif breaches == 1:
            status = ControlHealthStatus.AMBER
        else:
            status = ControlHealthStatus.GREEN

        return ControlHealthRecord(
            control_id=control_id, kpi_name=kpi_name,
            status=status, current_value=current, target=None,
            last_signal_time=last_seen.isoformat(),
            consecutive_breaches=breaches,
        )

    def baseline_stats(self, control_id: str, kpi_name: str) -> dict:
        """Return mean and stdev of recent window — used for anomaly thresholds.""""
        key = (control_id, kpi_name)
        values = [v for _, v in self._windows.get(key, [])]
        if len(values) < 5:
            return {"mean": None, "stdev": None, "n": len(values)}
        return {
            "mean": statistics.mean(values),
            "stdev": statistics.stdev(values),
            "n": len(values),
        }

from dataclasses import dataclass
from datetime import date
import statistics

@dataclass
class ModelDriftSample:
    sample_date: date
    model_id: str
    metric_name: str     # "auroc", "accuracy", "f1", "calibration_error"
    metric_value: float
    baseline_value: float   # From initial validation

    @property
    def relative_degradation(self) -> float:
        """Positive means worse than baseline.""""
        if self.baseline_value == 0:
            return 0.0
        return (self.baseline_value - self.metric_value) / self.baseline_value

    @property
    def is_material_drift(self) -> bool:
        return self.relative_degradation > 0.05   # > 5% degradation

class ModelDriftMonitor:
    DRIFT_WINDOW = 4    # Alert if drift seen in N consecutive samples

    def __init__(self, signal_bus):
        self._bus = signal_bus
        self._history: dict[str, list[ModelDriftSample]] = {}

    def record(self, sample: ModelDriftSample) -> None:
        key = f"{sample.model_id}:{sample.metric_name}"
        if key not in self._history:
            self._history[key] = []
        self._history[key].append(sample)

        recent = self._history[key][-self.DRIFT_WINDOW:]
        if len(recent) >= self.DRIFT_WINDOW and all(s.is_material_drift for s in recent):
            self._bus.emit(ControlSignal(
                source=SignalSource.MODEL_MONITOR,
                control_id="CCM-007",
                kpi_name=f"drift_{sample.metric_name}",
                kpi_value=sample.metric_value,
                kpi_unit=sample.metric_name,
                severity=SignalSeverity.CRITICAL,
                threshold_breached=True,
                details={
                    "model_id": sample.model_id,
                    "baseline": sample.baseline_value,
                    "current": sample.metric_value,
                    "degradation_pct": round(sample.relative_degradation * 100, 1),
                    "consecutive_samples": self.DRIFT_WINDOW,
                },
            ))

    def drift_report(self, model_id: str) -> list[dict]:
        report = []
        for key, samples in self._history.items():
            if not key.startswith(model_id):
                continue
            metric = key.split(":", 1)[1]
            values = [s.metric_value for s in samples]
            report.append({
                "metric": metric,
                "baseline": samples[0].baseline_value if samples else None,
                "current": values[-1] if values else None,
                "min": min(values) if values else None,
                "samples": len(values),
                "material_drift": any(s.is_material_drift for s in samples),
            })
        return report

