# Map control IDs to the regulatory regimes they satisfy
CONTROL_REGIME_MAP: dict[str, list[str]] = {
    "CCM-001": ["SOC2-CC6.1", "NYDFS-500.06", "PCI-DSS-Req10"],
    "CCM-002": ["SOC2-CC6.7", "NYDFS-500.06"],
    "CCM-003": ["SOC2-CC6.1", "NYDFS-500.12", "PCI-DSS-Req8"],
    "CCM-004": ["SOC2-A1.2", "EU-AI-Act-Art13"],
    "CCM-005": ["SOC2-CC9.2", "PCI-DSS-Req12"],
    "CCM-006": ["SOC2-CC7.2", "EU-AI-Act-Art9"],
    "CCM-007": ["SR-11-7", "EU-AI-Act-Art72"],
    "CCM-008": ["SOC2-CC6.1", "HIPAA-164.312a"],
    "CCM-009": ["PCI-DSS-Req4", "NYDFS-500.07"],
}

@dataclass
class RegimeHealthSummary:
    regime: str
    green_controls: int
    amber_controls: int
    red_controls: int
    grey_controls: int

    @property
    def overall_status(self) -> str:
        if self.red_controls > 0:
            return "RED"
        if self.amber_controls > 0 or self.grey_controls > 0:
            return "AMBER"
        return "GREEN"

def compute_regime_health(
    aggregator: CCMAggregator,
    kpi_definitions: list[dict],   # [{control_id, kpi_name}]
) -> dict[str, RegimeHealthSummary]:
    regime_counts: dict[str, dict[str, int]] = {}

    for kpi_def in kpi_definitions:
        ctrl_id = kpi_def["control_id"]
        health = aggregator.health(ctrl_id, kpi_def["kpi_name"])
        for regime in CONTROL_REGIME_MAP.get(ctrl_id, []):
            if regime not in regime_counts:
                regime_counts[regime] = {"green":0,"amber":0,"red":0,"grey":0}
            status_map = {
                ControlHealthStatus.GREEN: "green",
                ControlHealthStatus.AMBER: "amber",
                ControlHealthStatus.RED:   "red",
                ControlHealthStatus.GREY:  "grey",
            }
            regime_counts[regime][status_map[health.status]] += 1

    return {
        regime: RegimeHealthSummary(
            regime=regime,
            green_controls=counts["green"],
            amber_controls=counts["amber"],
            red_controls=counts["red"],
            grey_controls=counts["grey"],
        )
        for regime, counts in regime_counts.items()
    }
